import { getQuery } from 'h3'

export default defineEventHandler(async (event) => {

  const query = getQuery(event)
  if(query){
    console.log(query)
    return query
  }

  const opts = {
    method: 'GET',
    url: `https://api.printify.com/v1/shops/6483145/orders/${query.id}.json`,
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer eyJ0eXAiOiJKV1QiLCJhbGciOiJSUzI1NiJ9..AH6QPYSJpX5z7YyO8dW5nTpS_CrorLN3gJDJ_k8v58waX1cBIkQCD5qTPE8hLLFFDr61lNgvUPpcCDXd0-Q',
    }
  }

  const result = await $fetch(opts.url, {method: 'GET', headers: opts.headers })

  
  return result
})